      new PdfHeader().Write(doc.Title);
      new PdfBody().Write(doc.Content);
      new PdfFooter().Write(doc.PageNum);
    } else if (format == "html") {
      new HtmlHeader().Write(doc.Title);
      new HtmlBody().Write(doc.Content);
      new HtmlFooter().Write(doc.PageNum);
    }
  }
}

