public class Document {
  public string Title { get; set; }
  public List<Page> Pages { get; set; }

  public Document DeepClone() {
    var clone = (Document)MemberwiseClone();
    clone.Pages = Pages.Select(p => p.Clone()).ToList();
    return clone;
  }
}

